import React, { useEffect, useState } from "react";
import axios from "axios";
import {
    Users,
    Trophy,
    BarChart3,
    Sparkles,
    ChevronRight,
    Search,
    School,
    ArrowUpRight,
    TrendingUp,
    LayoutGrid,
    Zap
} from "lucide-react";

interface student {
    handle: string;
    platform: string;
    cpulseRating: number;
    rating: number;
}

interface ClassStats {
    classId: string;
    totalStudents: number;
    avgCPulse: number;
    topPlatform: string;
    platformDistribution: Record<string, number>;
    leaderboard: student[];
}

export default function CollegeDashboard() {
    const [classes, setClasses] = useState<string[]>([]);
    const [selectedClass, setSelectedClass] = useState<string>("");
    const [stats, setStats] = useState<ClassStats | null>(null);
    const [insights, setInsights] = useState<string>("");
    const [loading, setLoading] = useState(false);
    const [loadingInsights, setLoadingInsights] = useState(false);
    const [search, setSearch] = useState("");

    useEffect(() => {
        fetchClasses();
    }, []);

    const fetchClasses = async () => {
        try {
            const res = await axios.get("http://localhost:5000/api/class/list");
            setClasses(res.data.classes);
            if (res.data.classes.length > 0) {
                handleSelectClass(res.data.classes[0]);
            }
        } catch (err) {
            console.error("Failed to fetch classes", err);
        }
    };

    const handleSelectClass = async (classId: string) => {
        setSelectedClass(classId);
        setLoading(true);
        try {
            const res = await axios.get(`http://localhost:5000/api/class/${classId}/stats`);
            setStats(res.data);

            // Fetch AI Insights
            setLoadingInsights(true);
            const insightRes = await axios.get(`http://localhost:5000/api/class/${classId}/ai-insights`);
            setInsights(insightRes.data.insights);
        } catch (err) {
            console.error("Failed to fetch stats", err);
        } finally {
            setLoading(false);
            setLoadingInsights(false);
        }
    };

    const filteredClasses = classes.filter(c => c.toLowerCase().includes(search.toLowerCase()));

    return (
        <div className="min-h-screen bg-[#f8fafc] dark:bg-gray-950 p-4 md:p-8 text-gray-900 dark:text-gray-100">
            <div className="max-w-7xl mx-auto space-y-8">

                {/* HEADER SECTION */}
                <div className="relative overflow-hidden bg-indigo-600 rounded-3xl p-8 md:p-12 text-white shadow-2xl transition-all duration-500 hover:shadow-indigo-500/20">
                    <div className="relative z-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                        <div>
                            <div className="flex items-center gap-2 text-indigo-100 mb-2">
                                <School size={20} />
                                <span className="text-sm font-medium tracking-wider uppercase">Institutional Pulse</span>
                            </div>
                            <h1 className="text-4xl md:text-5xl font-black mb-4 tracking-tight">College Dashboard</h1>
                            <p className="text-indigo-100 max-w-xl text-lg opacity-90">
                                Tracking mastery across classes and celebrating the collective growth of our competitive programming community.
                            </p>
                        </div>

                        <div className="flex flex-col gap-4 w-full md:w-auto">
                            <div className="relative group">
                                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-white/50 group-focus-within:text-white transition-colors" size={20} />
                                <input
                                    type="text"
                                    placeholder="Search classes..."
                                    value={search}
                                    onChange={(e) => setSearch(e.target.value)}
                                    className="w-full md:w-64 pl-12 pr-4 py-3 bg-white/10 backdrop-blur-md border border-white/20 rounded-2xl focus:outline-none focus:ring-2 focus:ring-white/30 text-white placeholder:text-white/40 transition-all font-medium"
                                />
                            </div>
                        </div>
                    </div>
                    {/* Decorative Background Circles */}
                    <div className="absolute top-0 right-0 w-64 h-64 bg-white/10 rounded-full -translate-y-1/2 translate-x-1/2 blur-3xl" />
                    <div className="absolute bottom-0 left-0 w-32 h-32 bg-indigo-400/20 rounded-full translate-y-1/2 -translate-x-1/2 blur-2xl" />
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">

                    {/* CLASS LIST SIDEBAR */}
                    <div className="lg:col-span-1 space-y-4">
                        <div className="flex items-center gap-2 px-2 mb-2 font-bold text-gray-500 dark:text-gray-400 uppercase text-xs tracking-widest">
                            <LayoutGrid size={14} />
                            Active Classes
                        </div>
                        <div className="flex flex-row lg:flex-col overflow-x-auto lg:overflow-visible gap-2 pb-2 lg:pb-0 scrollbar-hide">
                            {filteredClasses.map((c) => (
                                <button
                                    key={c}
                                    onClick={() => handleSelectClass(c)}
                                    className={`flex items-center justify-between px-6 py-4 rounded-2xl whitespace-nowrap lg:whitespace-normal transition-all duration-300 group ${selectedClass === c
                                            ? "bg-white dark:bg-gray-800 shadow-xl shadow-indigo-500/10 border-l-4 border-indigo-600 scale-[1.02]"
                                            : "hover:bg-gray-100 dark:hover:bg-gray-800/50 text-gray-500 hover:text-gray-900 dark:hover:text-white"
                                        }`}
                                >
                                    <span className="font-bold">{c}</span>
                                    <ChevronRight className={`transition-transform duration-300 ${selectedClass === c ? "translate-x-1 text-indigo-600" : "opacity-0"}`} size={18} />
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* MAIN CONTENT AREA */}
                    <div className="lg:col-span-3 space-y-8">

                        {loading ? (
                            <div className="space-y-8 animate-pulse">
                                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                    {[1, 2, 3].map(i => <div key={i} className="h-32 bg-gray-200 dark:bg-gray-800 rounded-3xl" />)}
                                </div>
                                <div className="h-64 bg-gray-200 dark:bg-gray-800 rounded-3xl" />
                                <div className="h-96 bg-gray-200 dark:bg-gray-800 rounded-3xl" />
                            </div>
                        ) : stats ? (
                            <>
                                {/* STATS GRID */}
                                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                    <StatCard
                                        icon={<Users className="text-blue-500" />}
                                        label="Collective Strength"
                                        value={stats.totalStudents}
                                        sub="Enrolled Students"
                                        color="blue"
                                    />
                                    <StatCard
                                        icon={<TrendingUp className="text-emerald-500" />}
                                        label="Avg Class Pulse"
                                        value={stats.avgCPulse}
                                        sub="Global Avg Rank Score"
                                        color="emerald"
                                    />
                                    <StatCard
                                        icon={<Zap className="text-amber-500" />}
                                        label="Primary Platform"
                                        value={stats.topPlatform}
                                        sub="Most popular hub"
                                        color="amber"
                                        isText
                                    />
                                </div>

                                {/* AI INSIGHTS BOX */}
                                <div className="bg-white dark:bg-gray-800 rounded-3xl p-6 md:p-8 shadow-xl border border-gray-100 dark:border-gray-700 relative overflow-hidden group">
                                    <div className="flex items-center gap-3 mb-6 relative z-10">
                                        <div className="p-2 bg-indigo-100 dark:bg-indigo-900/40 rounded-xl text-indigo-600">
                                            <Sparkles size={24} className="animate-pulse" />
                                        </div>
                                        <h2 className="text-xl font-bold tracking-tight uppercase tracking-widest text-xs text-indigo-600 dark:text-indigo-400">Class Performance Insights</h2>
                                    </div>

                                    <div className="prose dark:prose-invert max-w-none relative z-10">
                                        {loadingInsights ? (
                                            <div className="space-y-3">
                                                <div className="h-4 bg-gray-100 dark:bg-gray-700 rounded-full w-3/4"></div>
                                                <div className="h-4 bg-gray-100 dark:bg-gray-700 rounded-full w-1/2"></div>
                                                <div className="h-4 bg-gray-100 dark:bg-gray-700 rounded-full w-5/6"></div>
                                            </div>
                                        ) : (
                                            <div className="text-gray-600 dark:text-gray-300 leading-relaxed font-medium">
                                                {insights.split('\n').map((line, i) => (
                                                    <p key={i} className="mb-2">{line}</p>
                                                ))}
                                            </div>
                                        )}
                                    </div>
                                    <div className="absolute -bottom-12 -right-12 w-48 h-48 bg-indigo-500/5 rounded-full group-hover:scale-125 transition-transform duration-700 blur-2xl" />
                                </div>

                                {/* LEADERBOARD TABLE */}
                                <div className="bg-white dark:bg-gray-800 rounded-3xl shadow-xl overflow-hidden border border-gray-100 dark:border-gray-700">
                                    <div className="p-6 md:p-8 border-b border-gray-100 dark:border-gray-700 flex justify-between items-center bg-gray-50/50 dark:bg-gray-800/50">
                                        <div className="flex items-center gap-3">
                                            <Trophy className="text-amber-500" size={24} />
                                            <h2 className="text-xl font-bold">Class Leaderboard</h2>
                                        </div>
                                        <div className="px-3 py-1 bg-gray-100 dark:bg-gray-700 text-gray-500 dark:text-gray-400 rounded-lg text-xs font-bold uppercase tracking-widest">
                                            {selectedClass}
                                        </div>
                                    </div>
                                    <div className="overflow-x-auto">
                                        <table className="w-full text-left border-collapse">
                                            <thead>
                                                <tr className="bg-gray-50/50 dark:bg-gray-900/30 text-gray-400 dark:text-gray-500 text-xs font-black uppercase tracking-widest">
                                                    <th className="px-8 py-5 font-black">Rank</th>
                                                    <th className="px-8 py-5 font-black">Student</th>
                                                    <th className="px-8 py-5 font-black">Platform</th>
                                                    <th className="px-8 py-5 text-right font-black">Rating</th>
                                                    <th className="px-8 py-5 text-right font-black">CPulse Score</th>
                                                    <th className="px-8 py-5"></th>
                                                </tr>
                                            </thead>
                                            <tbody>
                                                {stats.leaderboard.map((student, i) => (
                                                    <tr key={student.handle} className="group hover:bg-indigo-50/30 dark:hover:bg-indigo-900/10 transition-colors border-b last:border-0 border-gray-100 dark:border-gray-700/50">
                                                        <td className="px-8 py-5">
                                                            <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-black text-sm
                                                                ${i === 0 ? "bg-amber-100 text-amber-600" :
                                                                    i === 1 ? "bg-slate-200 text-slate-600" :
                                                                        i === 2 ? "bg-orange-100 text-orange-600" :
                                                                            "text-gray-400"}`}>
                                                                {i + 1}
                                                            </div>
                                                        </td>
                                                        <td className="px-8 py-5">
                                                            <span className="font-bold text-gray-900 dark:text-gray-100">{student.handle}</span>
                                                        </td>
                                                        <td className="px-8 py-5">
                                                            <span className={`px-2 py-1 rounded text-[10px] uppercase font-black tracking-wider
                                                                ${student.platform === 'codeforces' ? 'bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400' :
                                                                    student.platform === 'leetcode' ? 'bg-amber-100 text-amber-600 dark:bg-amber-900/30 dark:text-amber-400' :
                                                                        'bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400'}`}>
                                                                {student.platform}
                                                            </span>
                                                        </td>
                                                        <td className="px-8 py-5 text-right font-medium text-gray-500 dark:text-gray-400">
                                                            {student.rating || 'N/A'}
                                                        </td>
                                                        <td className="px-8 py-5 text-right">
                                                            <span className="font-black text-indigo-600 dark:text-indigo-400 text-lg">{student.cpulseRating}</span>
                                                        </td>
                                                        <td className="px-8 py-5 text-right">
                                                            <a
                                                                href={`/growth/${student.platform}/${student.handle}`}
                                                                className="p-2 opacity-0 group-hover:opacity-100 transition-all hover:bg-white dark:hover:bg-gray-700 rounded-lg text-indigo-600 flex items-center justify-end"
                                                            >
                                                                <ArrowUpRight size={18} />
                                                            </a>
                                                        </td>
                                                    </tr>
                                                ))}
                                            </tbody>
                                        </table>
                                    </div>
                                </div>
                            </>
                        ) : (
                            <div className="flex flex-col items-center justify-center py-20 bg-white dark:bg-gray-800 rounded-3xl shadow-xl border border-gray-100 dark:border-gray-700">
                                <School size={64} className="text-gray-200 dark:text-gray-700 mb-6" />
                                <h3 className="text-2xl font-bold mb-2">No Class Selected</h3>
                                <p className="text-gray-500 dark:text-gray-400">Please choose a class from the sidebar to view detailed analytics.</p>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

function StatCard({ icon, label, value, sub, color, isText }: any) {
    const colorClasses: any = {
        blue: "text-blue-600 bg-blue-50 dark:bg-blue-900/20",
        emerald: "text-emerald-600 bg-emerald-50 dark:bg-emerald-900/20",
        amber: "text-amber-600 bg-amber-50 dark:bg-amber-900/20",
    };

    return (
        <div className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-xl border border-gray-100 dark:border-gray-700 transition-all duration-300 hover:scale-[1.02] hover:-translate-y-1">
            <div className="flex justify-between items-start mb-4">
                <div className={`p-3 rounded-2xl ${colorClasses[color]}`}>
                    {React.cloneElement(icon, { size: 24 })}
                </div>
                <ArrowUpRight className="text-gray-300 dark:text-gray-600" size={18} />
            </div>
            <div>
                <p className="text-sm font-bold text-gray-400 dark:text-gray-500 uppercase tracking-widest leading-none mb-1">{label}</p>
                <div className="flex items-baseline gap-2">
                    <h3 className={`text-4xl font-black tracking-tight ${isText ? 'text-2xl pt-2 capitalize' : ''}`}>{value}</h3>
                </div>
                <p className="text-xs text-gray-500 mt-2 font-medium opacity-80">{sub}</p>
            </div>
        </div>
    );
}
